package main

import (
	"fmt"
)
func main() {
    var qtd, baruel int
    fmt.Scan(&qtd, &baruel)
    rep := ""
    falt := ""

    album :=  make([]int, qtd)
    num := 0
    for range baruel {
        fmt.Scan(&num)
        album[num - 1] ++
    }

    for i := range qtd {
        if album[i] != 0{
            for j := range (album[i])-1 {
                if j < (album[i])-2 {
                    rep += fmt.Sprintf("%d ", i + 1)
                }else {
                    rep += fmt.Sprintf("%d", i + 1)
                }
            }
        }else {
            if i != qtd - 1 {
                falt += fmt.Sprintf("%d ", i + 1)
            }else {
                falt += fmt.Sprintf("%d", i + 1)
            }
        }
    }
    if falt == ""{
        falt = "N"
    }
    if rep == ""{
        rep = "N"
    }
    fmt.Println(rep)
    fmt.Println(falt)
}
